PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE accounts (
    id TEXT PRIMARY KEY,
    spotify_user_id TEXT NOT NULL,
    display_name TEXT,
    email TEXT,
    access_token TEXT NOT NULL,
    refresh_token TEXT NOT NULL,
    token_expires_at INTEGER NOT NULL,
    created_at TEXT DEFAULT (datetime('now')),
    updated_at TEXT DEFAULT (datetime('now'))
  , auth_app_key TEXT DEFAULT 'default');
CREATE TABLE master_groups (
    id TEXT PRIMARY KEY,
    name TEXT NOT NULL,
    master_playlist_id TEXT,
    master_playlist_name TEXT,
    master_account_id TEXT,
    created_at TEXT DEFAULT (datetime('now')),
    updated_at TEXT DEFAULT (datetime('now')),
    FOREIGN KEY (master_account_id) REFERENCES accounts(id) ON DELETE SET NULL
  );
CREATE TABLE child_playlists (
    id TEXT PRIMARY KEY,
    group_id TEXT NOT NULL,
    playlist_id TEXT NOT NULL,
    playlist_name TEXT,
    account_id TEXT NOT NULL,
    created_at TEXT DEFAULT (datetime('now')), last_synced_at TEXT, track_count INTEGER DEFAULT 0,
    FOREIGN KEY (group_id) REFERENCES master_groups(id) ON DELETE CASCADE,
    FOREIGN KEY (account_id) REFERENCES accounts(id) ON DELETE CASCADE
  );
CREATE TABLE sync_logs (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    group_id TEXT NOT NULL,
    status TEXT NOT NULL,
    details TEXT,
    created_at TEXT DEFAULT (datetime('now')),
    FOREIGN KEY (group_id) REFERENCES master_groups(id) ON DELETE CASCADE
  );
CREATE TABLE trades (
    id TEXT PRIMARY KEY,
    name TEXT,
    track_uris TEXT NOT NULL,
    playlist_ids TEXT NOT NULL,
    duration_days INTEGER NOT NULL DEFAULT 28,
    created_at TEXT DEFAULT (datetime('now')),
    expires_at TEXT NOT NULL,
    status TEXT DEFAULT 'active',
    notes TEXT
  );
COMMIT;
